patterns.template:
# Trigger {count} RPC calls (generic fetch loop).
for _i in range({count}):
    page.evaluate('''async () => {{
        await fetch('/web/dataset/call_kw', {{
            method: 'POST',
            headers: {{'Content-Type': 'application/json'}},
            credentials: 'same-origin',
            body: JSON.stringify({{jsonrpc: '2.0', method: 'call',
                params: {{model: 'res.partner', method: 'search_count',
                          args: [[]], kwargs: {{}}}}}})
        }});
    }}''')

# Arm the interceptor to tag the NEXT request as shadow=true (ASYNC).
page.evaluate('''() => {{
    const m = odoo && odoo.__DEBUG__ && odoo.__DEBUG__.services
        && odoo.__DEBUG__.services['<project_namespace>.HotpotInterceptor'];
    if (m && m._setPendingShadowForTest) m._setPendingShadowForTest(true);
}}''')

# Visually lock UI before the request → recipe says this must be tagged BLOCK.
page.evaluate('''() => {{
    const f = odoo && odoo.__DEBUG__ && odoo.__DEBUG__.services
        && odoo.__DEBUG__.services['web.framework'];
    if (f && f.blockUI) f.blockUI();
}}''')
